export const privacyT = {
  it: {
    meta: { title: 'Privacy Policy | Hotel Langhe & Monferrato', desc: 'Informativa privacy ai sensi del GDPR per Hotel Langhe & Monferrato.' },
    header: { hotel: 'HOTEL LANGHE & MONFERRATO ★★★★', title: 'INFORMATIVA SUL TRATTAMENTO DEI DATI PERSONALI', gdpr: 'ai sensi degli artt. 13 e 14 del Regolamento (UE) 2016/679 (GDPR)', updated: 'Ultimo aggiornamento: 13 maggio 2026' },
    s1: { title: '1. Titolare del Trattamento', colLabel: 'Dato', colValue: 'Valore', r: { company: 'Ragione sociale', brand: 'Brand / Nome commerciale', legal: 'Sede legale (Italimpianti S.r.l.)', operative: 'Sede operativa (Hotel)', vat: 'Codice Fiscale / P.IVA', phone: 'Telefono', email: 'E-mail', pec: 'PEC', privacy: 'Responsabile Privacy interno', privacyVal: 'Da nominare – contattare via e-mail o PEC' }, desc: "Italimpianti S.r.l. è la società titolare del trattamento che gestisce, tra le proprie attività, l'Hotel Langhe & Monferrato, struttura alberghiera a quattro stelle con sede in Asti. Nel presente documento i termini \"Titolare\" e \"Hotel\" si riferiscono pertanto a Italimpianti S.r.l. nella sua veste di gestore della predetta struttura ricettiva e del relativo sito web." },
    s2: { title: "2. Consenso e Ricontatto da Parte dell'Hotel", text: "Accettando la presente Informativa e, ove richiesto, prestando il proprio consenso, l'interessato autorizza espressamente Hotel Langhe & Monferrato (Italimpianti S.r.l.) a ricontattarlo tramite i recapiti forniti (telefono, WhatsApp, e-mail) per finalità di marketing diretto, invio di offerte, promozioni, pacchetti speciali e comunicazioni commerciali relative ai servizi dell'Hotel. Il consenso è liberamente revocabile in qualsiasi momento, senza conseguenze, scrivendo ai recapiti indicati nell'art. 1." },
    s3: { title: '3. Tipologie di Dati Personali Trattati', sub1: "3.1 Dati forniti direttamente dall'interessato", items1: ['Nome, cognome, numero di telefono cellulare, indirizzo e-mail;', 'Messaggi e contenuti trasmessi tramite WhatsApp Business o contatto telefonico;', "Preferenze di soggiorno, richieste speciali e manifestazioni di interesse ai servizi dell'Hotel."], sub2: '3.2 Dati raccolti automaticamente tramite il sito web', items2: ['<b>Dati di navigazione:</b> indirizzo IP, tipo di browser, sistema operativo, pagine visitate, durata della sessione, URL di provenienza, data e ora di accesso – trattati anche tramite l\'infrastruttura Vercel Inc.;', '<b>Dati comportamentali:</b> movimenti del mouse, clic, scroll, registrazioni di sessione anonimizzate – raccolti tramite Microsoft Clarity;', '<b>Dati analitici aggregati:</b> metriche di traffico, provenienza geografica, dispositivi – raccolti tramite Google Analytics 4;', '<b>Dati di retargeting:</b> cookie ID, identificativi pubblicitari, hash anonimi di e-mail o telefono – trattati tramite Meta Pixel e Google Ads.'] },
    s4: { title: '4. Finalità e Basi Giuridiche del Trattamento', colPurpose: 'Finalità', colTools: 'Strumenti', colBasis: 'Base giuridica (art. 6 GDPR)', rows: [['A – Risposta a richieste e preventivi','WhatsApp, Zoho Mail, telefono','Art. 6.1.b) – misure precontrattuali'],['B – Ricontatto commerciale utenti interessati','WhatsApp, Zoho Mail, telefono','Art. 6.1.b) / 6.1.f) – legittimo interesse'],['C – Marketing: offerte, promozioni, pacchetti','WhatsApp, Zoho Mail, telefono','Art. 6.1.a) – consenso espresso'],['D – Retargeting Meta e Google','Meta Pixel, Google Ads','Art. 6.1.a) – consenso cookie banner'],['E – Analisi comportamento utenti','Google Analytics 4, Microsoft Clarity','Art. 6.1.a) – consenso cookie banner'],['F – Misurazione performance campagne','Google Ads, Meta Pixel','Art. 6.1.a) / 6.1.f)'],['G – Comunicazioni transazionali','Zoho Mail','Art. 6.1.b) – esecuzione contrattuale'],['H – Prevenzione frodi','Log di sistema','Art. 6.1.f) – legittimo interesse'],['I – Adempimenti legali, fiscali e contabili','–','Art. 6.1.c) – obbligo di legge']], note: 'Il consenso alle finalità C, D ed E è revocabile in qualsiasi momento. La revoca non pregiudica la liceità del trattamento effettuato anteriormente (art. 7, par. 3, GDPR).' },
    s5: { title: '5. Strumenti di Tracciamento e Fornitori Terzi', subs: [{ title: '5.1 Meta Pixel (Facebook Pixel)', text: 'Il sito utilizza Meta Pixel, strumento di tracciamento fornito da Meta Platforms Ireland Ltd. (4 Grand Canal Square, Dublino 2, Irlanda). Consente di misurare le conversioni delle campagne pubblicitarie su Facebook e Instagram, creare audience personalizzate e attivare il retargeting verso utenti che hanno visitato il sito. I dati possono essere trasmessi su server negli USA con garanzie ai sensi del Data Privacy Framework EU-USA. Informativa: ' },{ title: '5.2 Google Analytics 4', text: 'Il sito utilizza Google Analytics 4, fornito da Google Ireland Ltd. (Gordon House, Barrow Street, Dublino 4, Irlanda). Raccoglie dati di navigazione in forma aggregata e pseudonimizzata per analizzare il comportamento degli utenti. Gli indirizzi IP sono anonimizzati prima della trasmissione. Opt-out: ' },{ title: '5.3 Google Ads', text: "Il Titolare utilizza Google Ads (Google Ireland Ltd.) per campagne pubblicitarie su rete di ricerca, display e remarketing. I dati possono transitare su server negli USA nell'ambito del Data Privacy Framework EU-USA." },{ title: '5.4 Microsoft Clarity', text: 'Il sito utilizza Microsoft Clarity, fornito da Microsoft Ireland Operations Ltd. (One Microsoft Place, South County Business Park, Leopardstown, Dublino 18, Irlanda). Registra sessioni di navigazione anonimizzate per migliorare l\'usabilità del sito. I dati sono conservati per 30 giorni. Informativa: ' },{ title: '5.5 Zoho Mail', text: 'Per le comunicazioni via e-mail il Titolare utilizza Zoho Mail, fornito da Zoho Corporation B.V. (Beneluxlaan 4B, 3527 HX Utrecht, Paesi Bassi), che agisce quale Responsabile del Trattamento. Informativa: ' },{ title: '5.6 Google reCAPTCHA', text: 'I moduli di contatto presenti sul sito utilizzano Google reCAPTCHA, servizio anti-spam fornito da Google Ireland Ltd. Il servizio raccoglie e analizza il comportamento dell\'utente (indirizzo IP, movimenti del mouse, dati di sessione) al fine di distinguere le interazioni umane da quelle automatizzate. Informativa Google: ' }] },
    s5b: { title: '5-bis. Contitolarità con Meta Platforms Ireland Ltd.', p1: "Ai sensi della giurisprudenza della Corte di Giustizia dell'UE (sentenza C-40/17, Fashion ID, del 29 luglio 2019), l'utilizzo del Meta Pixel comporta una relazione di contitolarità del trattamento tra il Titolare e Meta Platforms Ireland Ltd.", p2: 'In qualità di contitolari, il Titolare e Meta hanno stipulato un accordo di contitolarità (Controller Addendum) ai sensi dell\'art. 26 GDPR, disponibile all\'indirizzo: ' },
    s6: { title: '6. Infrastruttura di Hosting: Vercel Inc.', text: 'Il sito è ospitato su infrastruttura cloud fornita da Vercel Inc. (340 Pine Street, Suite 701, San Francisco, CA 94104, USA), Responsabile del Trattamento ex art. 28 GDPR. I dati di navigazione transitano attraverso i server Vercel. Il trasferimento verso gli USA avviene tramite Clausole Contrattuali Standard (SCC) e nel rispetto del Data Privacy Framework EU-USA. Informativa: ' },
    s7: { title: '7. Trasferimento di Dati verso Paesi Extra-UE', text: "Nella gestione del sito web, i dati personali degli utenti potrebbero essere trasferiti su server ubicati negli Stati Uniti d'America. Il trasferimento avviene nel rispetto della Decisione di Adeguatezza della Commissione Europea n. 2023/1795 del 10 luglio 2023, che ha istituito il Data Privacy Framework EU-USA (DPF)." },
    s8: { title: '8. Trattamento tramite WhatsApp Business', text: "Il Titolare utilizza WhatsApp Business (Meta Platforms Ireland Ltd.) per ricevere richieste e inviare comunicazioni commerciali. L'invio di comunicazioni promozionali tramite WhatsApp richiede il preventivo consenso espresso dell'interessato. I messaggi transitano sui server di Meta. L'interessato può bloccare le comunicazioni in qualsiasi momento." },
    s9: { title: '9. Comunicazione e Destinatari dei Dati', intro: 'I dati potranno essere comunicati, nei limiti strettamente necessari, alle seguenti categorie di destinatari:', items: ["Personale autorizzato di Italimpianti S.r.l. addetto alla gestione dell'Hotel;", 'Fornitori IT e di hosting: Vercel Inc., Zoho Corporation, Microsoft, Google, Meta;', 'Piattaforme advertising: Meta Platforms Ireland Ltd., Google Ireland Ltd.;', 'Consulenti esterni (commercialisti, legali, revisori) nei limiti degli obblighi di legge;', 'Autorità pubbliche e giudiziarie nei casi previsti dalla normativa vigente.'], note: '<b>I dati non sono venduti né ceduti a terzi per finalità proprie di questi ultimi.</b>' },
    s10: { title: '10. Periodo di Conservazione dei Dati', intro: 'I dati personali sono conservati per il tempo strettamente necessario all\'erogazione dei servizi richiesti e al perseguimento delle finalità per cui sono stati raccolti.', colPurpose: 'Finalità / Strumento', colPeriod: 'Periodo di conservazione', rows: [['Contatti commerciali (finalità A, B)',"24 mesi dall'ultimo contatto utile"],['Marketing e promozioni (finalità C)','Fino a revoca del consenso, max 24 mesi'],['Retargeting – Meta Pixel, Google Ads (D)','Durata campagna + max 12 mesi'],['Analytics – Google Analytics 4 (E)','26 mesi (conforme Linee Guida Garante)'],['Microsoft Clarity – sessioni (E)','30 giorni'],['E-mail – Zoho Mail, comunicazioni transazionali (G)','5 anni dalla comunicazione'],['Prevenzione frodi e log di sicurezza (H)','12 mesi, salvo necessità di conservazione per indagini'],['Obblighi legali, fiscali e contabili (I)','10 anni (art. 2220 c.c. e D.P.R. 600/1973)']], closing: 'Scaduti i termini indicati, i dati vengono cancellati in modo sicuro o resi definitivamente anonimi e non ricollegabili all\'interessato.' },
    s11: { title: "11. Diritti dell'Interessato", intro: 'Ai sensi degli artt. 15-22 GDPR, l\'interessato può esercitare in qualsiasi momento i seguenti diritti scrivendo al Titolare ai recapiti indicati nell\'art. 1:', items: ['<b>Revocare il consenso (art. 7.3 GDPR):</b> L\'interessato può revocare in qualsiasi momento il consenso al trattamento dei propri dati.','<b>Opporsi al trattamento (art. 21 GDPR):</b> L\'interessato può opporsi al trattamento dei propri dati adducendo motivi connessi alla propria situazione particolare.','<b>Accedere ai propri dati (art. 15 GDPR):</b> L\'interessato ha diritto di ottenere conferma del trattamento e di accedere ai propri dati.','<b>Rettificare i propri dati (art. 16 GDPR):</b> L\'interessato ha diritto di ottenere la rettifica dei dati inesatti.','<b>Ottenere la limitazione del trattamento (art. 18 GDPR):</b> L\'interessato può richiedere che il trattamento sia limitato alla sola conservazione.','<b>Diritto all\'oblio (art. 17 GDPR):</b> L\'interessato ha diritto di ottenere la cancellazione dei propri dati personali.','<b>Portabilità dei dati (art. 20 GDPR):</b> L\'interessato ha diritto di ricevere i propri dati in un formato strutturato.','<b>Proporre reclamo:</b> L\'interessato ha diritto di proporre reclamo al Garante per la Protezione dei Dati Personali (www.garanteprivacy.it, tel. +39 06 69677 1).'], note: 'Il Titolare risponde alle richieste di esercizio dei diritti entro 30 giorni dal ricevimento.' },
    s12: { title: '12. Assenza di Decisioni Automatizzate e Profilazione', text: "Il Titolare dichiara che nella gestione dei dati personali non vengono adottati processi decisionali basati unicamente sul trattamento automatizzato che producano effetti giuridici sull'interessato. Le attività di analisi comportamentale e di retargeting pubblicitario non determinano alcuna decisione automatizzata con effetti sulla sfera giuridica dell'interessato." },
    s13: { title: '13. Cookie e Tecnologie di Tracciamento', text: "Il sito utilizza cookie tecnici (necessari al funzionamento) e cookie di profilazione/marketing (Meta Pixel, Google Analytics 4, Google Ads, Microsoft Clarity). I cookie non tecnici sono installati esclusivamente previo consenso espresso tramite cookie banner, conforme al Provvedimento del Garante n. 231 del 10 giugno 2021. Il consenso può essere revocato in qualsiasi momento tramite le impostazioni del banner o del browser." },
    s14: { title: '14. Misure di Sicurezza', text: "Il Titolare adotta misure tecniche e organizzative adeguate ai sensi dell'art. 32 GDPR, tra cui: crittografia in transito (HTTPS/TLS), controllo degli accessi basato sul principio del need-to-know, backup periodici, monitoraggio delle vulnerabilità e piani di risposta agli incidenti." },
    s15: { title: '15. Tutela dei Minori', text: "I servizi digitali del Titolare non sono destinati a soggetti di età inferiore a 16 anni. Qualora vengano rilevati dati di minori raccolti senza il consenso del titolare della responsabilità genitoriale, il Titolare provvederà alla loro immediata cancellazione." },
    s16: { title: '16. Modifiche alla Presente Informativa', text: "Il Titolare si riserva di aggiornare la presente Informativa in caso di variazioni normative o modifiche ai trattamenti effettuati. Le modifiche sostanziali saranno comunicate tramite avviso sul sito o via e-mail. La versione vigente è sempre consultabile sul sito ufficiale dell'Hotel." },
    footer: { reg: 'Informativa redatta ai sensi del Regolamento (UE) 2016/679 (GDPR) e del D.Lgs. 196/2003 s.m.i.', company: 'Italimpianti S.r.l. – Hotel Langhe & Monferrato', address: 'Via del Lavoro 23, 14100 Asti (AT)', date: '13 maggio 2026' },
  },
  en: {
    meta: { title: 'Privacy Policy | Hotel Langhe & Monferrato', desc: 'Privacy notice pursuant to GDPR for Hotel Langhe & Monferrato.' },
    header: { hotel: 'HOTEL LANGHE & MONFERRATO ★★★★', title: 'PRIVACY NOTICE – PERSONAL DATA PROCESSING', gdpr: 'pursuant to Articles 13 and 14 of Regulation (EU) 2016/679 (GDPR)', updated: 'Last updated: 13 May 2026' },
    s1: { title: '1. Data Controller', colLabel: 'Field', colValue: 'Value', r: { company: 'Company name', brand: 'Brand / Trade name', legal: 'Registered office (Italimpianti S.r.l.)', operative: 'Operational address (Hotel)', vat: 'Tax code / VAT number', phone: 'Phone', email: 'E-mail', pec: 'Certified e-mail (PEC)', privacy: 'Internal Privacy Officer', privacyVal: 'To be appointed – contact via e-mail or PEC' }, desc: 'Italimpianti S.r.l. is the data controller managing, among other activities, Hotel Langhe & Monferrato, a four-star hotel located in Asti. Throughout this document the terms "Controller" and "Hotel" refer to Italimpianti S.r.l. in its capacity as operator of the hotel and its website.' },
    s2: { title: '2. Consent and Re-contact by the Hotel', text: 'By accepting this Notice and, where required, giving their consent, the data subject expressly authorises Hotel Langhe & Monferrato (Italimpianti S.r.l.) to contact them via the provided details (phone, WhatsApp, e-mail) for direct marketing purposes, including offers, promotions, special packages and commercial communications related to the Hotel\'s services. Consent may be freely withdrawn at any time without consequences by writing to the contacts listed in art. 1.' },
    s3: { title: '3. Categories of Personal Data Processed', sub1: '3.1 Data provided directly by the data subject', items1: ['First and last name, mobile phone number, e-mail address;', 'Messages and content sent via WhatsApp Business or phone;', "Stay preferences, special requests and expressions of interest in the Hotel's services."], sub2: '3.2 Data collected automatically via the website', items2: ['<b>Navigation data:</b> IP address, browser type, operating system, pages visited, session duration, referral URL, date and time of access – processed also via Vercel Inc. infrastructure;', '<b>Behavioural data:</b> mouse movements, clicks, scroll, anonymised session recordings – collected via Microsoft Clarity;', '<b>Aggregate analytics data:</b> traffic metrics, geographic origin, devices – collected via Google Analytics 4;', '<b>Retargeting data:</b> cookie IDs, advertising identifiers, anonymous hashes of e-mail or phone – processed via Meta Pixel and Google Ads.'] },
    s4: { title: '4. Purposes and Legal Bases for Processing', colPurpose: 'Purpose', colTools: 'Tools', colBasis: 'Legal basis (Art. 6 GDPR)', rows: [['A – Responding to enquiries and quotes','WhatsApp, Zoho Mail, phone','Art. 6.1.b) – pre-contractual measures'],['B – Commercial re-contact of interested users','WhatsApp, Zoho Mail, phone','Art. 6.1.b) / 6.1.f) – legitimate interest'],['C – Marketing: offers, promotions, packages','WhatsApp, Zoho Mail, phone','Art. 6.1.a) – explicit consent'],['D – Meta and Google retargeting','Meta Pixel, Google Ads','Art. 6.1.a) – cookie banner consent'],['E – User behaviour analysis','Google Analytics 4, Microsoft Clarity','Art. 6.1.a) – cookie banner consent'],['F – Measuring campaign performance','Google Ads, Meta Pixel','Art. 6.1.a) / 6.1.f)'],['G – Transactional communications','Zoho Mail','Art. 6.1.b) – contract performance'],['H – Fraud prevention','System logs','Art. 6.1.f) – legitimate interest'],['I – Legal, tax and accounting obligations','–','Art. 6.1.c) – legal obligation']], note: 'Consent to purposes C, D and E may be withdrawn at any time. Withdrawal does not affect the lawfulness of processing carried out before withdrawal (Art. 7(3) GDPR).' },
    s5: { title: '5. Tracking Tools and Third-Party Providers', subs: [{ title: '5.1 Meta Pixel (Facebook Pixel)', text: 'The site uses Meta Pixel, a tracking tool provided by Meta Platforms Ireland Ltd. (4 Grand Canal Square, Dublin 2, Ireland). It measures conversions from Facebook and Instagram advertising campaigns, creates custom audiences and enables retargeting of site visitors. Data may be transferred to US servers under the EU–US Data Privacy Framework. Privacy policy: ' },{ title: '5.2 Google Analytics 4', text: 'The site uses Google Analytics 4, provided by Google Ireland Ltd. (Gordon House, Barrow Street, Dublin 4, Ireland). It collects aggregated and pseudonymised navigation data to analyse user behaviour. IP addresses are anonymised before transmission. Opt-out: ' },{ title: '5.3 Google Ads', text: 'The Controller uses Google Ads (Google Ireland Ltd.) for search, display and remarketing campaigns. Data may transit US servers under the EU–US Data Privacy Framework.' },{ title: '5.4 Microsoft Clarity', text: 'The site uses Microsoft Clarity, provided by Microsoft Ireland Operations Ltd. (One Microsoft Place, South County Business Park, Leopardstown, Dublin 18, Ireland). It records anonymised browsing sessions to improve site usability. Data are retained for 30 days. Privacy statement: ' },{ title: '5.5 Zoho Mail', text: 'For e-mail communications the Controller uses Zoho Mail, provided by Zoho Corporation B.V. (Beneluxlaan 4B, 3527 HX Utrecht, Netherlands), acting as data processor. Privacy policy: ' },{ title: '5.6 Google reCAPTCHA', text: 'Contact forms on the site use Google reCAPTCHA, an anti-spam service provided by Google Ireland Ltd. The service collects and analyses user behaviour (IP address, mouse movements, session data) to distinguish human interactions from automated ones. Google privacy policy: ' }] },
    s5b: { title: '5-bis. Joint Controllership with Meta Platforms Ireland Ltd.', p1: 'Pursuant to the case-law of the Court of Justice of the EU (judgment C-40/17, Fashion ID, 29 July 2019), the use of Meta Pixel creates a joint-controllership relationship between the Controller and Meta Platforms Ireland Ltd.', p2: 'As joint controllers, the Controller and Meta have entered into a joint controller agreement (Controller Addendum) pursuant to Art. 26 GDPR, available at: ' },
    s6: { title: '6. Hosting Infrastructure: Vercel Inc.', text: 'The site is hosted on cloud infrastructure provided by Vercel Inc. (340 Pine Street, Suite 701, San Francisco, CA 94104, USA), data processor pursuant to Art. 28 GDPR. Navigation data transit through Vercel servers. Transfers to the USA take place via Standard Contractual Clauses (SCC) and the EU–US Data Privacy Framework. Privacy policy: ' },
    s7: { title: '7. Transfers of Data to Non-EU Countries', text: 'In operating the website, users\' personal data may be transferred to servers located in the United States of America. Transfers take place in accordance with European Commission Adequacy Decision No. 2023/1795 of 10 July 2023, which established the EU–US Data Privacy Framework (DPF).' },
    s8: { title: '8. Processing via WhatsApp Business', text: 'The Controller uses WhatsApp Business (Meta Platforms Ireland Ltd.) to receive enquiries and send commercial communications. Sending promotional communications via WhatsApp requires the prior express consent of the data subject. Messages transit Meta\'s servers. The data subject may block communications at any time.' },
    s9: { title: '9. Disclosure and Recipients of Data', intro: 'Data may be disclosed, to the extent strictly necessary, to the following categories of recipients:', items: ['Authorised personnel of Italimpianti S.r.l. responsible for Hotel management;', 'IT and hosting providers: Vercel Inc., Zoho Corporation, Microsoft, Google, Meta;', 'Advertising platforms: Meta Platforms Ireland Ltd., Google Ireland Ltd.;', 'External consultants (accountants, lawyers, auditors) within the limits of legal obligations;', 'Public and judicial authorities in cases provided for by applicable law.'], note: '<b>Data are not sold or transferred to third parties for their own purposes.</b>' },
    s10: { title: '10. Data Retention Periods', intro: 'Personal data are retained for the time strictly necessary to provide the requested services and pursue the purposes for which they were collected.', colPurpose: 'Purpose / Tool', colPeriod: 'Retention period', rows: [['Commercial contacts (purposes A, B)','24 months from last useful contact'],['Marketing and promotions (purpose C)','Until consent is withdrawn, max 24 months'],['Retargeting – Meta Pixel, Google Ads (D)','Campaign duration + max 12 months'],['Analytics – Google Analytics 4 (E)','26 months (in line with Data Protection Authority guidelines)'],['Microsoft Clarity – sessions (E)','30 days'],['E-mail – Zoho Mail, transactional communications (G)','5 years from communication'],['Fraud prevention and security logs (H)','12 months, unless retention is required for investigations'],['Legal, tax and accounting obligations (I)','10 years (Italian Civil Code art. 2220 and Presidential Decree 600/1973)']], closing: 'Upon expiry of the indicated periods, data are securely deleted or permanently anonymised and no longer linkable to the data subject.' },
    s11: { title: '11. Rights of the Data Subject', intro: 'Pursuant to Arts. 15–22 GDPR, the data subject may at any time exercise the following rights by writing to the Controller at the contacts listed in art. 1:', items: ['<b>Withdraw consent (Art. 7.3 GDPR):</b> The data subject may withdraw consent to the processing of their data at any time.','<b>Object to processing (Art. 21 GDPR):</b> The data subject may object to processing on grounds relating to their particular situation.','<b>Access data (Art. 15 GDPR):</b> The data subject has the right to obtain confirmation of processing and access to their data.','<b>Rectify data (Art. 16 GDPR):</b> The data subject has the right to obtain rectification of inaccurate data.','<b>Restrict processing (Art. 18 GDPR):</b> The data subject may request that processing be restricted to storage only.','<b>Erasure (Art. 17 GDPR):</b> The data subject has the right to obtain erasure of their personal data.','<b>Data portability (Art. 20 GDPR):</b> The data subject has the right to receive their data in a structured format.','<b>Lodge a complaint:</b> The data subject has the right to lodge a complaint with the Italian Data Protection Authority (www.garanteprivacy.it, tel. +39 06 69677 1).'], note: 'The Controller responds to requests to exercise rights within 30 days of receipt.' },
    s12: { title: '12. Absence of Automated Decision-Making and Profiling', text: 'The Controller declares that no automated decision-making processes that produce legal effects on the data subject are used in managing personal data. Behavioural analysis and advertising retargeting activities do not result in any automated decision with legal effects on the data subject.' },
    s13: { title: '13. Cookies and Tracking Technologies', text: 'The site uses technical cookies (necessary for operation) and profiling/marketing cookies (Meta Pixel, Google Analytics 4, Google Ads, Microsoft Clarity). Non-technical cookies are installed exclusively with express consent via the cookie banner, in compliance with the Italian Data Protection Authority Provision No. 231 of 10 June 2021. Consent may be withdrawn at any time via the banner settings or the browser.' },
    s14: { title: '14. Security Measures', text: 'The Controller adopts appropriate technical and organisational measures pursuant to Art. 32 GDPR, including: encryption in transit (HTTPS/TLS), access control based on the need-to-know principle, regular backups, vulnerability monitoring and incident response plans.' },
    s15: { title: '15. Protection of Minors', text: 'The Controller\'s digital services are not intended for persons under the age of 16. Should data relating to minors collected without the consent of the holder of parental responsibility be detected, the Controller will proceed to their immediate deletion.' },
    s16: { title: '16. Changes to This Notice', text: 'The Controller reserves the right to update this Notice in the event of regulatory changes or modifications to the processing carried out. Material changes will be communicated via notice on the site or by e-mail. The current version is always available on the Hotel\'s official website.' },
    footer: { reg: 'Notice prepared pursuant to Regulation (EU) 2016/679 (GDPR) and Italian Legislative Decree 196/2003 as amended.', company: 'Italimpianti S.r.l. – Hotel Langhe & Monferrato', address: 'Via del Lavoro 23, 14100 Asti (AT)', date: '13 May 2026' },
  },
  fr: {
    meta: { title: 'Politique de confidentialité | Hotel Langhe & Monferrato', desc: 'Politique de confidentialité conformément au RGPD pour Hotel Langhe & Monferrato.' },
    header: { hotel: 'HOTEL LANGHE & MONFERRATO ★★★★', title: 'POLITIQUE DE CONFIDENTIALITÉ – TRAITEMENT DES DONNÉES PERSONNELLES', gdpr: 'conformément aux articles 13 et 14 du Règlement (UE) 2016/679 (RGPD)', updated: 'Dernière mise à jour: 13 mai 2026' },
    s1: { title: '1. Responsable du Traitement', colLabel: 'Champ', colValue: 'Valeur', r: { company: 'Raison sociale', brand: 'Marque / Nom commercial', legal: 'Siège social (Italimpianti S.r.l.)', operative: "Adresse opérationnelle (Hôtel)", vat: 'Code fiscal / TVA', phone: 'Téléphone', email: 'E-mail', pec: 'E-mail certifié (PEC)', privacy: 'Délégué à la protection des données interne', privacyVal: 'À nommer – contacter par e-mail ou PEC' }, desc: "Italimpianti S.r.l. est la société responsable du traitement qui gère, parmi ses activités, l'Hotel Langhe & Monferrato, établissement hôtelier quatre étoiles situé à Asti. Dans ce document, les termes \"Responsable\" et \"Hôtel\" désignent Italimpianti S.r.l. en sa qualité de gestionnaire de l'établissement et de son site web." },
    s2: { title: "2. Consentement et Recontact de la Part de l'Hôtel", text: "En acceptant la présente Politique et, le cas échéant, en donnant son consentement, la personne concernée autorise expressément Hotel Langhe & Monferrato (Italimpianti S.r.l.) à la recontacter via les coordonnées fournies (téléphone, WhatsApp, e-mail) à des fins de marketing direct, d'envoi d'offres, de promotions, de forfaits spéciaux et de communications commerciales relatives aux services de l'Hôtel. Le consentement peut être librement retiré à tout moment, sans conséquences, en écrivant aux coordonnées indiquées à l'art. 1." },
    s3: { title: '3. Catégories de Données Personnelles Traitées', sub1: '3.1 Données fournies directement par la personne concernée', items1: ['Prénom, nom de famille, numéro de téléphone mobile, adresse e-mail ;', 'Messages et contenus transmis via WhatsApp Business ou contact téléphonique ;', "Préférences de séjour, demandes spéciales et manifestations d'intérêt pour les services de l'Hôtel."], sub2: '3.2 Données collectées automatiquement via le site web', items2: ['<b>Données de navigation :</b> adresse IP, type de navigateur, système d\'exploitation, pages visitées, durée de la session, URL de provenance, date et heure d\'accès – traitées également via l\'infrastructure Vercel Inc. ;', '<b>Données comportementales :</b> mouvements de la souris, clics, défilement, enregistrements de session anonymisés – collectés via Microsoft Clarity ;', '<b>Données analytiques agrégées :</b> métriques de trafic, origine géographique, appareils – collectés via Google Analytics 4 ;', '<b>Données de retargeting :</b> identifiants de cookies, identifiants publicitaires, hachages anonymes d\'e-mail ou de téléphone – traités via Meta Pixel et Google Ads.'] },
    s4: { title: '4. Finalités et Bases Juridiques du Traitement', colPurpose: 'Finalité', colTools: 'Outils', colBasis: 'Base juridique (Art. 6 RGPD)', rows: [['A – Réponse aux demandes et devis','WhatsApp, Zoho Mail, téléphone','Art. 6.1.b) – mesures précontractuelles'],['B – Recontact commercial des utilisateurs intéressés','WhatsApp, Zoho Mail, téléphone','Art. 6.1.b) / 6.1.f) – intérêt légitime'],['C – Marketing : offres, promotions, forfaits','WhatsApp, Zoho Mail, téléphone','Art. 6.1.a) – consentement explicite'],['D – Retargeting Meta et Google','Meta Pixel, Google Ads','Art. 6.1.a) – consentement bandeau cookies'],['E – Analyse du comportement des utilisateurs','Google Analytics 4, Microsoft Clarity','Art. 6.1.a) – consentement bandeau cookies'],['F – Mesure des performances des campagnes','Google Ads, Meta Pixel','Art. 6.1.a) / 6.1.f)'],['G – Communications transactionnelles','Zoho Mail','Art. 6.1.b) – exécution du contrat'],['H – Prévention de la fraude','Journaux système','Art. 6.1.f) – intérêt légitime'],['I – Obligations légales, fiscales et comptables','–','Art. 6.1.c) – obligation légale']], note: 'Le consentement aux finalités C, D et E peut être retiré à tout moment. Le retrait ne porte pas atteinte à la licéité du traitement effectué avant celui-ci (Art. 7, par. 3, RGPD).' },
    s5: { title: '5. Outils de Suivi et Prestataires Tiers', subs: [{ title: '5.1 Meta Pixel (Facebook Pixel)', text: "Le site utilise Meta Pixel, outil de suivi fourni par Meta Platforms Ireland Ltd. (4 Grand Canal Square, Dublin 2, Irlande). Il mesure les conversions des campagnes publicitaires sur Facebook et Instagram, crée des audiences personnalisées et active le retargeting vers les visiteurs du site. Les données peuvent être transférées sur des serveurs aux États-Unis dans le cadre du Data Privacy Framework UE–États-Unis. Politique de confidentialité : " },{ title: '5.2 Google Analytics 4', text: "Le site utilise Google Analytics 4, fourni par Google Ireland Ltd. (Gordon House, Barrow Street, Dublin 4, Irlande). Il collecte des données de navigation agrégées et pseudonymisées pour analyser le comportement des utilisateurs. Les adresses IP sont anonymisées avant la transmission. Opt-out : " },{ title: '5.3 Google Ads', text: "Le Responsable utilise Google Ads (Google Ireland Ltd.) pour des campagnes publicitaires sur le réseau de recherche, display et remarketing. Les données peuvent transiter sur des serveurs aux États-Unis dans le cadre du Data Privacy Framework UE–États-Unis." },{ title: '5.4 Microsoft Clarity', text: "Le site utilise Microsoft Clarity, fourni par Microsoft Ireland Operations Ltd. (One Microsoft Place, South County Business Park, Leopardstown, Dublin 18, Irlande). Il enregistre des sessions de navigation anonymisées pour améliorer la convivialité du site. Les données sont conservées 30 jours. Déclaration de confidentialité : " },{ title: '5.5 Zoho Mail', text: "Pour les communications par e-mail, le Responsable utilise Zoho Mail, fourni par Zoho Corporation B.V. (Beneluxlaan 4B, 3527 HX Utrecht, Pays-Bas), agissant en qualité de sous-traitant. Politique de confidentialité : " },{ title: '5.6 Google reCAPTCHA', text: "Les formulaires de contact du site utilisent Google reCAPTCHA, service anti-spam fourni par Google Ireland Ltd. Le service collecte et analyse le comportement de l'utilisateur (adresse IP, mouvements de la souris, données de session) afin de distinguer les interactions humaines des interactions automatisées. Politique de confidentialité Google : " }] },
    s5b: { title: '5-bis. Coresponsabilité avec Meta Platforms Ireland Ltd.', p1: "Conformément à la jurisprudence de la Cour de justice de l'UE (arrêt C-40/17, Fashion ID, 29 juillet 2019), l'utilisation de Meta Pixel crée une relation de coresponsabilité du traitement entre le Responsable et Meta Platforms Ireland Ltd.", p2: "En tant que coresponsables, le Responsable et Meta ont conclu un accord de coresponsabilité (Controller Addendum) conformément à l'art. 26 RGPD, disponible à l'adresse : " },
    s6: { title: '6. Infrastructure d\'hébergement : Vercel Inc.', text: "Le site est hébergé sur l'infrastructure cloud fournie par Vercel Inc. (340 Pine Street, Suite 701, San Francisco, CA 94104, États-Unis), sous-traitant au sens de l'art. 28 RGPD. Les données de navigation transitent par les serveurs Vercel. Le transfert vers les États-Unis s'effectue via les Clauses Contractuelles Types (CCT) et le Data Privacy Framework UE–États-Unis. Politique de confidentialité : " },
    s7: { title: '7. Transferts de Données vers des Pays Hors UE', text: "Dans le cadre de la gestion du site web, les données personnelles des utilisateurs peuvent être transférées sur des serveurs situés aux États-Unis d'Amérique. Le transfert s'effectue conformément à la décision d'adéquation de la Commission européenne n° 2023/1795 du 10 juillet 2023, qui a instauré le Data Privacy Framework UE–États-Unis (DPF)." },
    s8: { title: '8. Traitement via WhatsApp Business', text: "Le Responsable utilise WhatsApp Business (Meta Platforms Ireland Ltd.) pour recevoir des demandes et envoyer des communications commerciales. L'envoi de communications promotionnelles via WhatsApp requiert le consentement préalable et explicite de la personne concernée. Les messages transitent par les serveurs de Meta. La personne concernée peut bloquer les communications à tout moment." },
    s9: { title: '9. Communication et Destinataires des Données', intro: 'Les données peuvent être communiquées, dans les limites strictement nécessaires, aux catégories de destinataires suivantes :', items: ["Personnel autorisé d'Italimpianti S.r.l. chargé de la gestion de l'Hôtel ;", 'Prestataires informatiques et d\'hébergement : Vercel Inc., Zoho Corporation, Microsoft, Google, Meta ;', 'Plateformes publicitaires : Meta Platforms Ireland Ltd., Google Ireland Ltd. ;', "Consultants externes (experts-comptables, juristes, auditeurs) dans les limites des obligations légales ;", 'Autorités publiques et judiciaires dans les cas prévus par la réglementation applicable.'], note: '<b>Les données ne sont pas vendues ni cédées à des tiers pour leurs propres finalités.</b>' },
    s10: { title: '10. Durées de Conservation des Données', intro: "Les données personnelles sont conservées pendant le temps strictement nécessaire à la fourniture des services demandés et à la poursuite des finalités pour lesquelles elles ont été collectées.", colPurpose: 'Finalité / Outil', colPeriod: 'Durée de conservation', rows: [['Contacts commerciaux (finalités A, B)','24 mois à compter du dernier contact utile'],['Marketing et promotions (finalité C)','Jusqu\'au retrait du consentement, max 24 mois'],['Retargeting – Meta Pixel, Google Ads (D)','Durée de la campagne + max 12 mois'],['Analytics – Google Analytics 4 (E)','26 mois (conformément aux lignes directrices de l\'autorité de protection des données)'],['Microsoft Clarity – sessions (E)','30 jours'],['E-mail – Zoho Mail, communications transactionnelles (G)','5 ans à compter de la communication'],['Prévention des fraudes et journaux de sécurité (H)','12 mois, sauf nécessité de conservation pour des enquêtes'],['Obligations légales, fiscales et comptables (I)','10 ans']], closing: "À l'expiration des délais indiqués, les données sont supprimées de manière sécurisée ou définitivement anonymisées et ne peuvent plus être rattachées à la personne concernée." },
    s11: { title: '11. Droits de la Personne Concernée', intro: "Conformément aux arts. 15 à 22 RGPD, la personne concernée peut à tout moment exercer les droits suivants en écrivant au Responsable aux coordonnées indiquées à l'art. 1 :", items: ['<b>Retirer le consentement (Art. 7.3 RGPD) :</b> La personne concernée peut retirer son consentement au traitement de ses données à tout moment.','<b>S\'opposer au traitement (Art. 21 RGPD) :</b> La personne concernée peut s\'opposer au traitement de ses données pour des raisons liées à sa situation particulière.','<b>Accéder à ses données (Art. 15 RGPD) :</b> La personne concernée a le droit d\'obtenir la confirmation du traitement et l\'accès à ses données.','<b>Rectifier ses données (Art. 16 RGPD) :</b> La personne concernée a le droit d\'obtenir la rectification des données inexactes.','<b>Limiter le traitement (Art. 18 RGPD) :</b> La personne concernée peut demander que le traitement soit limité à la seule conservation.','<b>Droit à l\'effacement (Art. 17 RGPD) :</b> La personne concernée a le droit d\'obtenir l\'effacement de ses données personnelles.','<b>Portabilité des données (Art. 20 RGPD) :</b> La personne concernée a le droit de recevoir ses données dans un format structuré.','<b>Introduire une réclamation :</b> La personne concernée a le droit d\'introduire une réclamation auprès de l\'autorité de contrôle compétente.'], note: 'Le Responsable répond aux demandes d\'exercice des droits dans les 30 jours suivant leur réception.' },
    s12: { title: '12. Absence de Décisions Automatisées et de Profilage', text: "Le Responsable déclare qu'aucun processus décisionnel fondé uniquement sur un traitement automatisé et produisant des effets juridiques sur la personne concernée n'est utilisé dans la gestion des données personnelles. Les activités d'analyse comportementale et de retargeting publicitaire n'aboutissent à aucune décision automatisée ayant des effets sur la sphère juridique de la personne concernée." },
    s13: { title: '13. Cookies et Technologies de Suivi', text: "Le site utilise des cookies techniques (nécessaires au fonctionnement) et des cookies de profilage/marketing (Meta Pixel, Google Analytics 4, Google Ads, Microsoft Clarity). Les cookies non techniques ne sont installés qu'après consentement explicite via le bandeau cookies, conformément à la réglementation applicable. Le consentement peut être retiré à tout moment via les paramètres du bandeau ou du navigateur." },
    s14: { title: '14. Mesures de Sécurité', text: "Le Responsable adopte des mesures techniques et organisationnelles appropriées conformément à l'art. 32 RGPD, notamment : chiffrement en transit (HTTPS/TLS), contrôle des accès fondé sur le principe du besoin d'en connaître, sauvegardes régulières, surveillance des vulnérabilités et plans de réponse aux incidents." },
    s15: { title: '15. Protection des Mineurs', text: "Les services numériques du Responsable ne sont pas destinés aux personnes de moins de 16 ans. Si des données relatives à des mineurs collectées sans le consentement du titulaire de la responsabilité parentale venaient à être détectées, le Responsable procéderait à leur suppression immédiate." },
    s16: { title: '16. Modifications de la Présente Politique', text: "Le Responsable se réserve le droit de mettre à jour la présente Politique en cas de modifications réglementaires ou de changements dans les traitements effectués. Les modifications substantielles seront communiquées via un avis sur le site ou par e-mail. La version en vigueur est toujours consultable sur le site officiel de l'Hôtel." },
    footer: { reg: 'Politique rédigée conformément au Règlement (UE) 2016/679 (RGPD) et au décret législatif italien 196/2003 tel que modifié.', company: 'Italimpianti S.r.l. – Hotel Langhe & Monferrato', address: 'Via del Lavoro 23, 14100 Asti (AT)', date: '13 mai 2026' },
  },
  de: {
    meta: { title: 'Datenschutzerklärung | Hotel Langhe & Monferrato', desc: 'Datenschutzerklärung gemäß DSGVO für Hotel Langhe & Monferrato.' },
    header: { hotel: 'HOTEL LANGHE & MONFERRATO ★★★★', title: 'DATENSCHUTZERKLÄRUNG – VERARBEITUNG PERSONENBEZOGENER DATEN', gdpr: 'gemäß Art. 13 und 14 der Verordnung (EU) 2016/679 (DSGVO)', updated: 'Letzte Aktualisierung: 13. Mai 2026' },
    s1: { title: '1. Verantwortlicher für die Verarbeitung', colLabel: 'Feld', colValue: 'Wert', r: { company: 'Firmenname', brand: 'Marke / Handelsname', legal: 'Eingetragener Sitz (Italimpianti S.r.l.)', operative: 'Betriebsadresse (Hotel)', vat: 'Steuernummer / USt-IdNr.', phone: 'Telefon', email: 'E-Mail', pec: 'Zertifizierte E-Mail (PEC)', privacy: 'Interner Datenschutzbeauftragter', privacyVal: 'Noch zu benennen – Kontakt per E-Mail oder PEC' }, desc: 'Italimpianti S.r.l. ist der Verantwortliche für die Verarbeitung, der unter anderem das Hotel Langhe & Monferrato, ein Vier-Sterne-Hotel in Asti, betreibt. In diesem Dokument beziehen sich die Begriffe „Verantwortlicher" und „Hotel" auf Italimpianti S.r.l. in ihrer Eigenschaft als Betreiberin des Hotels und der entsprechenden Website.' },
    s2: { title: '2. Einwilligung und Kontaktaufnahme durch das Hotel', text: 'Durch die Annahme dieser Erklärung und, soweit erforderlich, durch die Erteilung der Einwilligung, ermächtigt die betroffene Person Hotel Langhe & Monferrato (Italimpianti S.r.l.) ausdrücklich, sie über die angegebenen Kontaktdaten (Telefon, WhatsApp, E-Mail) für Direktmarketingzwecke, einschließlich Angebote, Aktionen, Sonderpakete und kommerzielle Mitteilungen zu den Dienstleistungen des Hotels zu kontaktieren. Die Einwilligung kann jederzeit ohne Konsequenzen widerrufen werden, indem man an die in Art. 1 angegebenen Kontakte schreibt.' },
    s3: { title: '3. Kategorien verarbeiteter personenbezogener Daten', sub1: '3.1 Vom Betroffenen direkt bereitgestellte Daten', items1: ['Vorname, Nachname, Mobiltelefonnummer, E-Mail-Adresse;', 'Nachrichten und Inhalte, die über WhatsApp Business oder per Telefon übermittelt wurden;', 'Aufenthaltspräferenzen, besondere Anfragen und Interessensbekundungen für die Dienstleistungen des Hotels.'], sub2: '3.2 Automatisch über die Website erfasste Daten', items2: ['<b>Navigationsdaten:</b> IP-Adresse, Browsertyp, Betriebssystem, besuchte Seiten, Sitzungsdauer, Referrer-URL, Datum und Uhrzeit des Zugriffs – auch über die Vercel Inc.-Infrastruktur verarbeitet;', '<b>Verhaltensdaten:</b> Mausbewegungen, Klicks, Scrollen, anonymisierte Sitzungsaufzeichnungen – erfasst über Microsoft Clarity;', '<b>Aggregierte Analysedaten:</b> Traffic-Metriken, geografische Herkunft, Geräte – erfasst über Google Analytics 4;', '<b>Retargeting-Daten:</b> Cookie-IDs, Werbe-IDs, anonyme Hashes von E-Mail oder Telefon – verarbeitet über Meta Pixel und Google Ads.'] },
    s4: { title: '4. Zwecke und Rechtsgrundlagen der Verarbeitung', colPurpose: 'Zweck', colTools: 'Instrumente', colBasis: 'Rechtsgrundlage (Art. 6 DSGVO)', rows: [['A – Beantwortung von Anfragen und Angeboten','WhatsApp, Zoho Mail, Telefon','Art. 6.1.b) – vorvertragliche Maßnahmen'],['B – Kommerzielle Wiederkontaktierung interessierter Nutzer','WhatsApp, Zoho Mail, Telefon','Art. 6.1.b) / 6.1.f) – berechtigtes Interesse'],['C – Marketing: Angebote, Aktionen, Pakete','WhatsApp, Zoho Mail, Telefon','Art. 6.1.a) – ausdrückliche Einwilligung'],['D – Retargeting Meta und Google','Meta Pixel, Google Ads','Art. 6.1.a) – Cookie-Banner-Einwilligung'],['E – Analyse des Nutzerverhaltens','Google Analytics 4, Microsoft Clarity','Art. 6.1.a) – Cookie-Banner-Einwilligung'],['F – Messung der Kampagnenleistung','Google Ads, Meta Pixel','Art. 6.1.a) / 6.1.f)'],['G – Transaktionsbezogene Mitteilungen','Zoho Mail','Art. 6.1.b) – Vertragserfüllung'],['H – Betrugsprävention','Systemprotokolle','Art. 6.1.f) – berechtigtes Interesse'],['I – Rechtliche, steuerliche und buchhalterische Pflichten','–','Art. 6.1.c) – rechtliche Verpflichtung']], note: 'Die Einwilligung in die Zwecke C, D und E kann jederzeit widerrufen werden. Der Widerruf berührt nicht die Rechtmäßigkeit der vor dem Widerruf erfolgten Verarbeitung (Art. 7 Abs. 3 DSGVO).' },
    s5: { title: '5. Tracking-Instrumente und Drittanbieter', subs: [{ title: '5.1 Meta Pixel (Facebook Pixel)', text: 'Die Website verwendet Meta Pixel, ein Tracking-Tool von Meta Platforms Ireland Ltd. (4 Grand Canal Square, Dublin 2, Irland). Es misst Conversions aus Facebook- und Instagram-Werbekampagnen, erstellt benutzerdefinierte Zielgruppen und ermöglicht Retargeting von Website-Besuchern. Daten können auf US-Server im Rahmen des EU-US Data Privacy Framework übertragen werden. Datenschutzrichtlinie: ' },{ title: '5.2 Google Analytics 4', text: 'Die Website verwendet Google Analytics 4 von Google Ireland Ltd. (Gordon House, Barrow Street, Dublin 4, Irland). Es erfasst aggregierte und pseudonymisierte Navigationsdaten zur Analyse des Nutzerverhaltens. IP-Adressen werden vor der Übertragung anonymisiert. Opt-out: ' },{ title: '5.3 Google Ads', text: 'Der Verantwortliche nutzt Google Ads (Google Ireland Ltd.) für Suchmaschinen-, Display- und Remarketing-Kampagnen. Daten können auf US-Server im Rahmen des EU-US Data Privacy Framework übertragen werden.' },{ title: '5.4 Microsoft Clarity', text: 'Die Website verwendet Microsoft Clarity von Microsoft Ireland Operations Ltd. (One Microsoft Place, South County Business Park, Leopardstown, Dublin 18, Irland). Es zeichnet anonymisierte Browsing-Sitzungen auf, um die Benutzerfreundlichkeit der Website zu verbessern. Daten werden 30 Tage aufbewahrt. Datenschutzerklärung: ' },{ title: '5.5 Zoho Mail', text: 'Für E-Mail-Kommunikation nutzt der Verantwortliche Zoho Mail von Zoho Corporation B.V. (Beneluxlaan 4B, 3527 HX Utrecht, Niederlande) als Auftragsverarbeiter. Datenschutzrichtlinie: ' },{ title: '5.6 Google reCAPTCHA', text: 'Kontaktformulare auf der Website verwenden Google reCAPTCHA, einen Anti-Spam-Dienst von Google Ireland Ltd. Der Dienst erfasst und analysiert das Nutzerverhalten (IP-Adresse, Mausbewegungen, Sitzungsdaten), um menschliche von automatisierten Interaktionen zu unterscheiden. Google-Datenschutzrichtlinie: ' }] },
    s5b: { title: '5-bis. Gemeinsame Verantwortlichkeit mit Meta Platforms Ireland Ltd.', p1: 'Gemäß der Rechtsprechung des EuGH (Urteil C-40/17, Fashion ID, 29. Juli 2019) begründet die Nutzung von Meta Pixel eine gemeinsame Verantwortlichkeit zwischen dem Verantwortlichen und Meta Platforms Ireland Ltd.', p2: 'Als gemeinsam Verantwortliche haben der Verantwortliche und Meta eine Vereinbarung zur gemeinsamen Verantwortlichkeit (Controller Addendum) gemäß Art. 26 DSGVO geschlossen, abrufbar unter: ' },
    s6: { title: '6. Hosting-Infrastruktur: Vercel Inc.', text: 'Die Website wird auf der Cloud-Infrastruktur von Vercel Inc. (340 Pine Street, Suite 701, San Francisco, CA 94104, USA) gehostet, Auftragsverarbeiter gemäß Art. 28 DSGVO. Navigationsdaten werden über Vercel-Server übertragen. Die Übermittlung in die USA erfolgt über Standardvertragsklauseln (SCC) und den EU-US Data Privacy Framework. Datenschutzrichtlinie: ' },
    s7: { title: '7. Datenübermittlung in Drittländer', text: 'Im Rahmen des Betriebs der Website können personenbezogene Daten auf Server in den Vereinigten Staaten übertragen werden. Die Übermittlung erfolgt gemäß dem Angemessenheitsbeschluss der Europäischen Kommission Nr. 2023/1795 vom 10. Juli 2023, der den EU-US Data Privacy Framework (DPF) eingeführt hat.' },
    s8: { title: '8. Verarbeitung über WhatsApp Business', text: 'Der Verantwortliche nutzt WhatsApp Business (Meta Platforms Ireland Ltd.) zum Empfang von Anfragen und zur Übermittlung kommerzieller Kommunikation. Das Versenden von Werbemitteilungen über WhatsApp erfordert die vorherige ausdrückliche Einwilligung der betroffenen Person. Nachrichten werden über Meta-Server übertragen. Die betroffene Person kann die Kommunikation jederzeit blockieren.' },
    s9: { title: '9. Übermittlung und Empfänger von Daten', intro: 'Daten können im streng erforderlichen Umfang an folgende Kategorien von Empfängern weitergegeben werden:', items: ['Autorisiertes Personal von Italimpianti S.r.l. für das Hotelmanagement;', 'IT- und Hosting-Anbieter: Vercel Inc., Zoho Corporation, Microsoft, Google, Meta;', 'Werbeplattformen: Meta Platforms Ireland Ltd., Google Ireland Ltd.;', 'Externe Berater (Steuerberater, Rechtsanwälte, Wirtschaftsprüfer) im Rahmen gesetzlicher Verpflichtungen;', 'Behörden und Gerichte in gesetzlich vorgesehenen Fällen.'], note: '<b>Daten werden nicht an Dritte für deren eigene Zwecke verkauft oder weitergegeben.</b>' },
    s10: { title: '10. Aufbewahrungsfristen', intro: 'Personenbezogene Daten werden so lange aufbewahrt, wie es für die Erbringung der angeforderten Dienste und die Verfolgung der Zwecke, für die sie erhoben wurden, erforderlich ist.', colPurpose: 'Zweck / Instrument', colPeriod: 'Aufbewahrungsfrist', rows: [['Kommerzielle Kontakte (Zwecke A, B)','24 Monate ab letztem nützlichen Kontakt'],['Marketing und Aktionen (Zweck C)','Bis zum Widerruf der Einwilligung, max. 24 Monate'],['Retargeting – Meta Pixel, Google Ads (D)','Kampagnendauer + max. 12 Monate'],['Analytics – Google Analytics 4 (E)','26 Monate (gemäß Leitlinien der Datenschutzbehörde)'],['Microsoft Clarity – Sitzungen (E)','30 Tage'],['E-Mail – Zoho Mail, transaktionale Kommunikation (G)','5 Jahre ab Kommunikation'],['Betrugsprävention und Sicherheitsprotokolle (H)','12 Monate, außer Aufbewahrung für Ermittlungen erforderlich'],['Gesetzliche, steuerliche und buchhalterische Pflichten (I)','10 Jahre']], closing: 'Nach Ablauf der angegebenen Fristen werden die Daten sicher gelöscht oder dauerhaft anonymisiert und können nicht mehr der betroffenen Person zugeordnet werden.' },
    s11: { title: '11. Rechte der Betroffenen Person', intro: 'Gemäß Art. 15–22 DSGVO kann die betroffene Person jederzeit folgende Rechte ausüben, indem sie dem Verantwortlichen unter den in Art. 1 genannten Kontaktdaten schreibt:', items: ['<b>Einwilligung widerrufen (Art. 7 Abs. 3 DSGVO):</b> Die betroffene Person kann ihre Einwilligung zur Verarbeitung ihrer Daten jederzeit widerrufen.','<b>Widerspruch einlegen (Art. 21 DSGVO):</b> Die betroffene Person kann der Verarbeitung aus Gründen, die sich aus ihrer besonderen Situation ergeben, widersprechen.','<b>Auskunft erhalten (Art. 15 DSGVO):</b> Die betroffene Person hat das Recht, eine Bestätigung der Verarbeitung zu erhalten und auf ihre Daten zuzugreifen.','<b>Berichtigung verlangen (Art. 16 DSGVO):</b> Die betroffene Person hat das Recht, die Berichtigung unrichtiger Daten zu verlangen.','<b>Verarbeitung einschränken (Art. 18 DSGVO):</b> Die betroffene Person kann verlangen, dass die Verarbeitung auf die reine Speicherung beschränkt wird.','<b>Löschung verlangen (Art. 17 DSGVO):</b> Die betroffene Person hat das Recht, die Löschung ihrer personenbezogenen Daten zu verlangen.','<b>Datenübertragbarkeit (Art. 20 DSGVO):</b> Die betroffene Person hat das Recht, ihre Daten in einem strukturierten Format zu erhalten.','<b>Beschwerde einreichen:</b> Die betroffene Person hat das Recht, eine Beschwerde bei der zuständigen Aufsichtsbehörde einzureichen.'], note: 'Der Verantwortliche beantwortet Anfragen zur Ausübung von Rechten innerhalb von 30 Tagen nach Eingang.' },
    s12: { title: '12. Keine automatisierten Entscheidungen und Profiling', text: 'Der Verantwortliche erklärt, dass bei der Verarbeitung personenbezogener Daten keine ausschließlich auf automatisierter Verarbeitung beruhenden Entscheidungsprozesse eingesetzt werden, die rechtliche Wirkungen für die betroffene Person entfalten. Verhaltensanalyse- und Werberetargeting-Aktivitäten führen zu keinen automatisierten Entscheidungen mit rechtlichen Auswirkungen auf die betroffene Person.' },
    s13: { title: '13. Cookies und Tracking-Technologien', text: 'Die Website verwendet technische Cookies (für den Betrieb notwendig) und Profiling-/Marketing-Cookies (Meta Pixel, Google Analytics 4, Google Ads, Microsoft Clarity). Nicht-technische Cookies werden ausschließlich nach ausdrücklicher Einwilligung über das Cookie-Banner installiert. Die Einwilligung kann jederzeit über die Banner-Einstellungen oder den Browser widerrufen werden.' },
    s14: { title: '14. Sicherheitsmaßnahmen', text: 'Der Verantwortliche trifft geeignete technische und organisatorische Maßnahmen gemäß Art. 32 DSGVO, darunter: Verschlüsselung bei der Übertragung (HTTPS/TLS), zugriffsbasierte Kontrolle nach dem Need-to-know-Prinzip, regelmäßige Backups, Schwachstellenüberwachung und Notfallpläne.' },
    s15: { title: '15. Schutz Minderjähriger', text: 'Die digitalen Dienste des Verantwortlichen richten sich nicht an Personen unter 16 Jahren. Sollten Daten Minderjähriger ohne Einwilligung des Inhabers der elterlichen Verantwortung erfasst worden sein, wird der Verantwortliche diese unverzüglich löschen.' },
    s16: { title: '16. Änderungen dieser Erklärung', text: 'Der Verantwortliche behält sich vor, diese Erklärung bei regulatorischen Änderungen oder Modifikationen der durchgeführten Verarbeitungen zu aktualisieren. Wesentliche Änderungen werden über einen Hinweis auf der Website oder per E-Mail mitgeteilt. Die aktuelle Version ist stets auf der offiziellen Website des Hotels verfügbar.' },
    footer: { reg: 'Erklärung gemäß Verordnung (EU) 2016/679 (DSGVO) und italienischem Gesetzesdekret 196/2003 in der geänderten Fassung.', company: 'Italimpianti S.r.l. – Hotel Langhe & Monferrato', address: 'Via del Lavoro 23, 14100 Asti (AT)', date: '13. Mai 2026' },
  },
  es: {
    meta: { title: 'Política de Privacidad | Hotel Langhe & Monferrato', desc: 'Política de privacidad conforme al RGPD para Hotel Langhe & Monferrato.' },
    header: { hotel: 'HOTEL LANGHE & MONFERRATO ★★★★', title: 'POLÍTICA DE PRIVACIDAD – TRATAMIENTO DE DATOS PERSONALES', gdpr: 'conforme a los artículos 13 y 14 del Reglamento (UE) 2016/679 (RGPD)', updated: 'Última actualización: 13 de mayo de 2026' },
    s1: { title: '1. Responsable del Tratamiento', colLabel: 'Campo', colValue: 'Valor', r: { company: 'Razón social', brand: 'Marca / Nombre comercial', legal: 'Sede social (Italimpianti S.r.l.)', operative: 'Dirección operativa (Hotel)', vat: 'Código fiscal / IVA', phone: 'Teléfono', email: 'Correo electrónico', pec: 'Correo electrónico certificado (PEC)', privacy: 'Delegado de Protección de Datos interno', privacyVal: 'Por designar – contactar por correo electrónico o PEC' }, desc: 'Italimpianti S.r.l. es la sociedad responsable del tratamiento que gestiona, entre otras actividades, el Hotel Langhe & Monferrato, establecimiento hotelero de cuatro estrellas situado en Asti. En este documento, los términos "Responsable" y "Hotel" se refieren a Italimpianti S.r.l. en su calidad de operadora del hotel y de su sitio web.' },
    s2: { title: '2. Consentimiento y Recontacto por Parte del Hotel', text: 'Al aceptar la presente Política y, cuando proceda, prestando su consentimiento, el interesado autoriza expresamente a Hotel Langhe & Monferrato (Italimpianti S.r.l.) a ponerse en contacto con él a través de los datos facilitados (teléfono, WhatsApp, correo electrónico) con fines de marketing directo, envío de ofertas, promociones, paquetes especiales y comunicaciones comerciales relativas a los servicios del Hotel. El consentimiento puede revocarse libremente en cualquier momento, sin consecuencias, escribiendo a los datos de contacto indicados en el art. 1.' },
    s3: { title: '3. Categorías de Datos Personales Tratados', sub1: '3.1 Datos facilitados directamente por el interesado', items1: ['Nombre, apellidos, número de teléfono móvil, dirección de correo electrónico;', 'Mensajes y contenidos transmitidos a través de WhatsApp Business o contacto telefónico;', 'Preferencias de estancia, solicitudes especiales y manifestaciones de interés en los servicios del Hotel.'], sub2: '3.2 Datos recopilados automáticamente a través del sitio web', items2: ['<b>Datos de navegación:</b> dirección IP, tipo de navegador, sistema operativo, páginas visitadas, duración de la sesión, URL de procedencia, fecha y hora de acceso – tratados también a través de la infraestructura de Vercel Inc.;', '<b>Datos de comportamiento:</b> movimientos del ratón, clics, desplazamiento, grabaciones de sesión anonimizadas – recopilados a través de Microsoft Clarity;', '<b>Datos analíticos agregados:</b> métricas de tráfico, origen geográfico, dispositivos – recopilados a través de Google Analytics 4;', '<b>Datos de retargeting:</b> ID de cookies, identificadores publicitarios, hashes anónimos de correo electrónico o teléfono – tratados a través de Meta Pixel y Google Ads.'] },
    s4: { title: '4. Finalidades y Bases Jurídicas del Tratamiento', colPurpose: 'Finalidad', colTools: 'Herramientas', colBasis: 'Base jurídica (Art. 6 RGPD)', rows: [['A – Respuesta a consultas y presupuestos','WhatsApp, Zoho Mail, teléfono','Art. 6.1.b) – medidas precontractuales'],['B – Recontacto comercial de usuarios interesados','WhatsApp, Zoho Mail, teléfono','Art. 6.1.b) / 6.1.f) – interés legítimo'],['C – Marketing: ofertas, promociones, paquetes','WhatsApp, Zoho Mail, teléfono','Art. 6.1.a) – consentimiento expreso'],['D – Retargeting Meta y Google','Meta Pixel, Google Ads','Art. 6.1.a) – consentimiento banner de cookies'],['E – Análisis del comportamiento de usuarios','Google Analytics 4, Microsoft Clarity','Art. 6.1.a) – consentimiento banner de cookies'],['F – Medición del rendimiento de campañas','Google Ads, Meta Pixel','Art. 6.1.a) / 6.1.f)'],['G – Comunicaciones transaccionales','Zoho Mail','Art. 6.1.b) – ejecución del contrato'],['H – Prevención del fraude','Registros del sistema','Art. 6.1.f) – interés legítimo'],['I – Obligaciones legales, fiscales y contables','–','Art. 6.1.c) – obligación legal']], note: 'El consentimiento a las finalidades C, D y E puede revocarse en cualquier momento. La revocación no afecta a la licitud del tratamiento realizado con anterioridad (Art. 7, apdo. 3, RGPD).' },
    s5: { title: '5. Herramientas de Seguimiento y Proveedores Terceros', subs: [{ title: '5.1 Meta Pixel (Facebook Pixel)', text: 'El sitio utiliza Meta Pixel, herramienta de seguimiento proporcionada por Meta Platforms Ireland Ltd. (4 Grand Canal Square, Dublín 2, Irlanda). Permite medir las conversiones de las campañas publicitarias en Facebook e Instagram, crear audiencias personalizadas y activar el retargeting hacia usuarios que han visitado el sitio. Los datos pueden transferirse a servidores en EE.UU. con garantías en virtud del Marco de Privacidad de Datos UE-EE.UU. Política de privacidad: ' },{ title: '5.2 Google Analytics 4', text: 'El sitio utiliza Google Analytics 4, proporcionado por Google Ireland Ltd. (Gordon House, Barrow Street, Dublín 4, Irlanda). Recopila datos de navegación de forma agregada y seudonimizada para analizar el comportamiento de los usuarios. Las direcciones IP se anonimizan antes de la transmisión. Exclusión: ' },{ title: '5.3 Google Ads', text: 'El Responsable utiliza Google Ads (Google Ireland Ltd.) para campañas publicitarias en redes de búsqueda, display y remarketing. Los datos pueden transitar por servidores en EE.UU. en el marco del Marco de Privacidad de Datos UE-EE.UU.' },{ title: '5.4 Microsoft Clarity', text: 'El sitio utiliza Microsoft Clarity, proporcionado por Microsoft Ireland Operations Ltd. (One Microsoft Place, South County Business Park, Leopardstown, Dublín 18, Irlanda). Registra sesiones de navegación anonimizadas para mejorar la usabilidad del sitio. Los datos se conservan durante 30 días. Declaración de privacidad: ' },{ title: '5.5 Zoho Mail', text: 'Para las comunicaciones por correo electrónico, el Responsable utiliza Zoho Mail, proporcionado por Zoho Corporation B.V. (Beneluxlaan 4B, 3527 HX Utrecht, Países Bajos), que actúa como encargado del tratamiento. Política de privacidad: ' },{ title: '5.6 Google reCAPTCHA', text: 'Los formularios de contacto del sitio utilizan Google reCAPTCHA, servicio antispam proporcionado por Google Ireland Ltd. El servicio recopila y analiza el comportamiento del usuario (dirección IP, movimientos del ratón, datos de sesión) para distinguir las interacciones humanas de las automatizadas. Política de privacidad de Google: ' }] },
    s5b: { title: '5-bis. Corresponsabilidad con Meta Platforms Ireland Ltd.', p1: 'De conformidad con la jurisprudencia del Tribunal de Justicia de la UE (sentencia C-40/17, Fashion ID, de 29 de julio de 2019), el uso de Meta Pixel implica una relación de corresponsabilidad del tratamiento entre el Responsable y Meta Platforms Ireland Ltd.', p2: 'En calidad de corresponsables, el Responsable y Meta han suscrito un acuerdo de corresponsabilidad (Controller Addendum) conforme al art. 26 RGPD, disponible en: ' },
    s6: { title: '6. Infraestructura de Alojamiento: Vercel Inc.', text: 'El sitio está alojado en la infraestructura en la nube proporcionada por Vercel Inc. (340 Pine Street, Suite 701, San Francisco, CA 94104, EE.UU.), encargado del tratamiento conforme al art. 28 RGPD. Los datos de navegación se transmiten a través de los servidores de Vercel. La transferencia a EE.UU. se realiza mediante Cláusulas Contractuales Tipo (CCT) y el Marco de Privacidad de Datos UE-EE.UU. Política de privacidad: ' },
    s7: { title: '7. Transferencia de Datos a Países No Pertenecientes a la UE', text: 'En la gestión del sitio web, los datos personales de los usuarios pueden transferirse a servidores ubicados en los Estados Unidos de América. La transferencia se realiza de conformidad con la Decisión de Adecuación de la Comisión Europea n.° 2023/1795 de 10 de julio de 2023, que estableció el Marco de Privacidad de Datos UE-EE.UU. (DPF).' },
    s8: { title: '8. Tratamiento a través de WhatsApp Business', text: 'El Responsable utiliza WhatsApp Business (Meta Platforms Ireland Ltd.) para recibir consultas y enviar comunicaciones comerciales. El envío de comunicaciones promocionales a través de WhatsApp requiere el consentimiento previo y expreso del interesado. Los mensajes se transmiten a través de los servidores de Meta. El interesado puede bloquear las comunicaciones en cualquier momento.' },
    s9: { title: '9. Comunicación y Destinatarios de los Datos', intro: 'Los datos podrán comunicarse, en la medida estrictamente necesaria, a las siguientes categorías de destinatarios:', items: ['Personal autorizado de Italimpianti S.r.l. encargado de la gestión del Hotel;', 'Proveedores de TI y alojamiento: Vercel Inc., Zoho Corporation, Microsoft, Google, Meta;', 'Plataformas publicitarias: Meta Platforms Ireland Ltd., Google Ireland Ltd.;', 'Consultores externos (contables, abogados, auditores) dentro de los límites de las obligaciones legales;', 'Autoridades públicas y judiciales en los casos previstos por la normativa aplicable.'], note: '<b>Los datos no se venden ni ceden a terceros para sus propias finalidades.</b>' },
    s10: { title: '10. Períodos de Conservación de los Datos', intro: 'Los datos personales se conservan durante el tiempo estrictamente necesario para la prestación de los servicios solicitados y el cumplimiento de las finalidades para las que fueron recopilados.', colPurpose: 'Finalidad / Herramienta', colPeriod: 'Período de conservación', rows: [['Contactos comerciales (finalidades A, B)','24 meses desde el último contacto útil'],['Marketing y promociones (finalidad C)','Hasta la revocación del consentimiento, máx. 24 meses'],['Retargeting – Meta Pixel, Google Ads (D)','Duración de la campaña + máx. 12 meses'],['Analytics – Google Analytics 4 (E)','26 meses (conforme a las directrices de la autoridad de protección de datos)'],['Microsoft Clarity – sesiones (E)','30 días'],['Correo electrónico – Zoho Mail, comunicaciones transaccionales (G)','5 años desde la comunicación'],['Prevención del fraude y registros de seguridad (H)','12 meses, salvo necesidad de conservación para investigaciones'],['Obligaciones legales, fiscales y contables (I)','10 años']], closing: 'Transcurridos los plazos indicados, los datos se eliminan de forma segura o se anonimizan definitivamente y no pueden vincularse al interesado.' },
    s11: { title: '11. Derechos del Interesado', intro: 'Conforme a los arts. 15 a 22 RGPD, el interesado puede ejercer en cualquier momento los siguientes derechos escribiendo al Responsable a los datos de contacto indicados en el art. 1:', items: ['<b>Revocar el consentimiento (Art. 7.3 RGPD):</b> El interesado puede revocar en cualquier momento su consentimiento al tratamiento de sus datos.','<b>Oponerse al tratamiento (Art. 21 RGPD):</b> El interesado puede oponerse al tratamiento de sus datos por motivos relacionados con su situación particular.','<b>Acceder a sus datos (Art. 15 RGPD):</b> El interesado tiene derecho a obtener confirmación del tratamiento y acceso a sus datos.','<b>Rectificar sus datos (Art. 16 RGPD):</b> El interesado tiene derecho a obtener la rectificación de los datos inexactos.','<b>Limitar el tratamiento (Art. 18 RGPD):</b> El interesado puede solicitar que el tratamiento se limite a la mera conservación.','<b>Supresión (Art. 17 RGPD):</b> El interesado tiene derecho a obtener la supresión de sus datos personales.','<b>Portabilidad de datos (Art. 20 RGPD):</b> El interesado tiene derecho a recibir sus datos en un formato estructurado.','<b>Presentar una reclamación:</b> El interesado tiene derecho a presentar una reclamación ante la autoridad de control competente.'], note: 'El Responsable responde a las solicitudes de ejercicio de derechos en el plazo de 30 días desde su recepción.' },
    s12: { title: '12. Ausencia de Decisiones Automatizadas y Elaboración de Perfiles', text: 'El Responsable declara que en la gestión de los datos personales no se emplean procesos de toma de decisiones basados únicamente en el tratamiento automatizado que produzcan efectos jurídicos en el interesado. Las actividades de análisis de comportamiento y retargeting publicitario no dan lugar a ninguna decisión automatizada con efectos sobre la esfera jurídica del interesado.' },
    s13: { title: '13. Cookies y Tecnologías de Seguimiento', text: 'El sitio utiliza cookies técnicas (necesarias para el funcionamiento) y cookies de elaboración de perfiles/marketing (Meta Pixel, Google Analytics 4, Google Ads, Microsoft Clarity). Las cookies no técnicas se instalan exclusivamente con consentimiento expreso a través del banner de cookies, de conformidad con la normativa aplicable. El consentimiento puede revocarse en cualquier momento a través de la configuración del banner o del navegador.' },
    s14: { title: '14. Medidas de Seguridad', text: 'El Responsable adopta medidas técnicas y organizativas adecuadas conforme al art. 32 RGPD, entre ellas: cifrado en tránsito (HTTPS/TLS), control de acceso basado en el principio de necesidad de conocer, copias de seguridad periódicas, supervisión de vulnerabilidades y planes de respuesta a incidentes.' },
    s15: { title: '15. Protección de Menores', text: 'Los servicios digitales del Responsable no están destinados a personas menores de 16 años. Si se detectaran datos de menores recopilados sin el consentimiento del titular de la responsabilidad parental, el Responsable procederá a su eliminación inmediata.' },
    s16: { title: '16. Modificaciones de la Presente Política', text: 'El Responsable se reserva el derecho de actualizar la presente Política en caso de cambios normativos o modificaciones en los tratamientos realizados. Los cambios sustanciales se comunicarán mediante un aviso en el sitio o por correo electrónico. La versión vigente siempre estará disponible en el sitio web oficial del Hotel.' },
    footer: { reg: 'Política redactada conforme al Reglamento (UE) 2016/679 (RGPD) y al Decreto Legislativo italiano 196/2003 en su versión modificada.', company: 'Italimpianti S.r.l. – Hotel Langhe & Monferrato', address: 'Via del Lavoro 23, 14100 Asti (AT)', date: '13 de mayo de 2026' },
  },
};
